/// <summary>
/// Controller class for ETGScaleTicketReport
/// </summary>
class ETGGrainReceiptReportController extends SrsReportRunController
{
}

Method.Source:
public static void main(Args _args)
{
    ETGGrainReceiptReportController controller = new ETGGrainReceiptReportController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGGrainReceiptReport, MainReport));
    controller.parmShowDialog(false);
    controller.startOperation();
}

public void prePromptModifyContract()
{
    ETGGrainReceiptNoteTable          grnTable = this.parmArgs().record();
    ETGGrainReceiptReportContract contract   = this.parmReportContract().parmRdpContract();
    contract.parmGrainReceiptNum(grnTable.GrainReceiptNoteId);
}
